import React, { useState } from 'react';
import { submitScreening } from '../api';

const phq = [
  "Little interest or pleasure in doing things",
  "Feeling down, depressed, or hopeless",
  "Trouble falling or staying asleep",
  "Feeling tired or having little energy",
  "Poor appetite or overeating",
  "Feeling bad about yourself",
  "Trouble concentrating",
  "Moving or speaking slowly or being fidgety",
  "Thoughts that you would be better off dead"
];

export default function Screening(){
  const [answers, setAnswers] = useState(Array(9).fill(0));
  const handle = (i,v)=>{ const a=[...answers]; a[i]=parseInt(v); setAnswers(a); };
  const submit = async (type) => {
    const res = await submitScreening(type, answers);
    alert(`Score ${res.score} — ${res.category}`);
  };
  return (
    <div style={{padding:20}}>
      <h2>PHQ-9 Screening (Gamified)</h2>
      <p>Earn points after submission.</p>
      {phq.map((q,i)=>(<div key={i} style={{marginBottom:10}}>
        <div>{i+1}. {q}</div>
        <select value={answers[i]} onChange={e=>handle(i,e.target.value)}>
          <option value={0}>Not at all (0)</option>
          <option value={1}>Several days (1)</option>
          <option value={2}>More than half the days (2)</option>
          <option value={3}>Nearly every day (3)</option>
        </select>
      </div>))}
      <button onClick={()=>submit('PHQ9')}>Submit PHQ-9</button>
    </div>
  );
}
